import{_ as e,p as a,q as s,a1 as n}from"./framework-5866ffd3.js";const r={},d=n(`<h1 id="rexec" tabindex="-1"><a class="header-anchor" href="#rexec" aria-hidden="true">#</a> rexec</h1><p>远程执行Linux系统下命令</p><h2 id="补充说明" tabindex="-1"><a class="header-anchor" href="#补充说明" aria-hidden="true">#</a> 补充说明</h2><p><strong>rexec命令</strong> 用于在指定的远程Linux系统主机上执行命令，向远程rexec服务器发出执行命令的请求。</p><p>rexec命令通过检查<code>$HOME/.netrc</code>文件（包含远程主机上使用的用户名和密码）来提供自动登录的功能。如果没有发现此类项或系统在安全方式下操作（参阅 securetcpip 命令），rexec命令提示输入一个远程主机的有效用户名和密码。这两种情况下，rexec均导致远程系统上的rexecd使用缺省的compat用户登录认证方法。rexecd不会为了备用的认证方法去查找<code>/etc/security/user</code>文件。也可以指定<code>-n</code>标志到rexec命令行上来重设自动登录功能。</p><h3 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>rexec<span class="token punctuation">(</span>选项<span class="token punctuation">)</span><span class="token punctuation">(</span>参数<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="选项" tabindex="-1"><a class="header-anchor" href="#选项" aria-hidden="true">#</a> 选项</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>-a：表示远程命令的标准错误与标准输出相同，不支持发送任意信号到远程进程；
-l<span class="token operator">&lt;</span>用户名<span class="token operator">&gt;</span>：指定连接远程rexec服务器的用户名；
-p<span class="token operator">&lt;</span>密码<span class="token operator">&gt;</span>：指定连接远程rexec服务器的密码；
-n：明确地提示输入用户名和密码。
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h3><ul><li>远程主机：指定远程主机（ip地址或主机名）；</li><li>命令：指定需要在远程主机上执行的命令。</li></ul><h3 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h3><p>要在一个远程主机上执行date命令，输入：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>rexec host1 <span class="token function">date</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>date命令的输出现在显示在本地系统上。本示例中，在本地主机上的<code>$HOME/.netrc</code>文件包含远程主机上有效的用户名和密码。如果没有远程主机的<code>$HOME/.netrc</code>文件中的有效项，将提示输入登录标识和密码。输入所要求的登录信息后，date命令的输出显示在本地系统上。</p><p>要重设自动登录功能并执行远程主机上的date命令，输入：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>rexec <span class="token parameter variable">-nhost1</span> <span class="token function">date</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>出现提示时输入用户名和密码，date命令的输出现在显示在本地系统上。</p><p>列出远程主机上另一个用户的目录，输入：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>rexec host1 <span class="token function">ls</span> <span class="token parameter variable">-l</span> /home/karen
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在远程主机host1上的karen 用户的目录列表显示在本地系统上。</p><p>如果没有远程主机的<code>$HOME/.netrc</code>文件中的有效项，将提示您输入登录标识和密码。输入要求的登录信息后，在远程主机host1上的karen用户的目录列表显示在本地系统上。</p>`,22),c=[d];function i(t,l){return a(),s("div",null,c)}const p=e(r,[["render",i],["__file","rexec.html.vue"]]);export{p as default};
